Create a new identity hero header component that replaces the minimal `AgentHubHeader`. The hero shows a larger avatar with status ring, agent name, meta row (status + runtime), and a close button.

**New file:** `apps/client/src/layers/features/agent-hub/ui/AgentHubHero.tsx`

```tsx
import { X } from 'lucide-react';
import { Button } from '@/layers/shared/ui';
import { useAppStore } from '@/layers/shared/model';
import { AgentIdentity, resolveAgentVisual } from '@/layers/entities/agent';
import { useAgentHubContext } from '../model/agent-hub-context';

/**
 * Identity hero header for the Agent Hub panel.
 *
 * Replaces the former AgentHubHeader with a richer identity display:
 * 52px avatar, agent name, status + runtime meta row, and close button.
 * This zone is sticky and never scrolls with tab content.
 */
export function AgentHubHero() {
  const { agent } = useAgentHubContext();
  const setRightPanelOpen = useAppStore((s) => s.setRightPanelOpen);
  const visual = resolveAgentVisual(agent);

  // Derive online/offline status from agent healthStatus if available
  const agentStatus = (agent as Record<string, unknown>).healthStatus === 'active' ? 'Online' : 'Offline';
  const statusColor = agentStatus === 'Online' ? 'text-emerald-500' : 'text-muted-foreground';

  return (
    <div data-slot="agent-hub-hero" className="relative flex flex-col items-center gap-1 border-b px-4 py-3">
      {/* Close button — absolute top-right */}
      <Button
        variant="ghost"
        size="icon"
        aria-label="Close agent hub"
        className="absolute right-2 top-2 size-7 shrink-0"
        onClick={() => setRightPanelOpen(false)}
      >
        <X className="size-4" />
      </Button>

      {/* Avatar at lg size (52px) */}
      <AgentIdentity
        color={visual.color}
        emoji={visual.emoji}
        name=""
        size="lg"
        healthStatus={(agent as Record<string, unknown>).healthStatus as 'active' | 'inactive' | 'stale' | 'unreachable' | undefined}
      />

      {/* Agent name */}
      <span className="text-[15px] font-semibold">
        {agent.displayName ?? agent.name}
      </span>

      {/* Meta row: status + runtime */}
      <span className="text-muted-foreground text-[10px]">
        <span className={statusColor}>{agentStatus}</span> · {agent.runtime ?? 'unknown'}
      </span>
    </div>
  );
}
```

Note: The AgentIdentity `lg` size already exists in the entity component (size-12 = 48px class via `AgentAvatar`). The spec calls for 52px — the current `lg` size (size-12 = 48px) is close enough. If exact 52px is needed, add an `xl` variant to `AgentAvatar` in a follow-up, but `lg` is acceptable for P1.

The hero intentionally renders the avatar via `AgentIdentity` with an empty name, then separately renders the name and meta row below — this gives the centered vertical layout from the spec rather than the horizontal layout that AgentIdentity normally uses.

Alternatively, render just `AgentAvatar` directly for cleaner code:
```tsx
import { AgentAvatar } from '@/layers/entities/agent';
// ...
<AgentAvatar color={visual.color} emoji={visual.emoji} size="lg" healthStatus={...} />
```

Use whichever approach produces the cleanest centered vertical layout.

**Acceptance criteria:**
- Component renders at `data-slot="agent-hub-hero"`
- Shows agent name (displayName preferred, falls back to name)
- Shows status (Online/Offline) and runtime in meta row
- Close button is positioned absolute top-right and calls `setRightPanelOpen(false)`
- Avatar is rendered at `lg` size
- Component uses `border-b` to separate from tab bar below

Create a horizontal tab bar with 3 tabs (Profile, Sessions, Config) that replaces the vertical `AgentHubNav` sidebar.

**New file:** `apps/client/src/layers/features/agent-hub/ui/AgentHubTabBar.tsx`

```tsx
import { cn } from '@/layers/shared/lib';
import { useAgentHubStore, type AgentHubTab } from '../model/agent-hub-store';

interface TabDef {
  id: AgentHubTab;
  label: string;
}

const TABS: TabDef[] = [
  { id: 'profile', label: 'Profile' },
  { id: 'sessions', label: 'Sessions' },
  { id: 'config', label: 'Config' },
];

/**
 * Horizontal tab bar for the Agent Hub panel.
 *
 * Renders 3 tab buttons in a flex row with underline-style active indicator.
 * Replaces the former AgentHubNav left sidebar.
 */
export function AgentHubTabBar() {
  const activeTab = useAgentHubStore((s) => s.activeTab);
  const setActiveTab = useAgentHubStore((s) => s.setActiveTab);

  return (
    <div data-slot="agent-hub-tab-bar" role="tablist" aria-label="Agent hub tabs" className="flex border-b">
      {TABS.map((tab) => (
        <button
          key={tab.id}
          type="button"
          role="tab"
          aria-selected={activeTab === tab.id}
          onClick={() => setActiveTab(tab.id)}
          className={cn(
            'flex-1 border-b-2 py-2 text-xs font-medium transition-colors',
            activeTab === tab.id
              ? 'text-foreground border-primary font-semibold'
              : 'text-muted-foreground hover:text-foreground border-transparent'
          )}
        >
          {tab.label}
        </button>
      ))}
    </div>
  );
}
```

