Create the ProfileTab component that replaces the old OverviewTab. It renders editable agent identity fields: display name, description, runtime selector, directory path (read-only), tags, and stats.

**New file:** `apps/client/src/layers/features/agent-hub/ui/tabs/ProfileTab.tsx`

```tsx
import { useState, useCallback } from 'react';
import { Folder, Plus, X } from 'lucide-react';
import { cn, getAgentDisplayName } from '@/layers/shared/lib';
import {
  Button,
  Input,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/layers/shared/ui';
import { useSessions } from '@/layers/entities/session';
import { useAgentHubContext } from '../../model/agent-hub-context';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';

/** Shorten a path by replacing $HOME prefix with ~. */
function tildeShorten(path: string): string {
  const home = typeof window !== 'undefined'
    ? (window as Record<string, unknown>).__DORKOS_HOME__ as string | undefined
    : undefined;
  if (home && path.startsWith(home)) {
    return '~' + path.slice(home.length);
  }
  return path;
}

/**
 * Profile tab for the Agent Hub panel.
 *
 * Renders editable agent identity fields: display name, description,
 * runtime selector, directory path, tags, and session/channel/task stats.
 */
export function ProfileTab() {
  const { agent, projectPath, onUpdate } = useAgentHubContext();
  const { sessions } = useSessions();

  // Local state for inline editing
  const [editingField, setEditingField] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [newTag, setNewTag] = useState('');
  const [showTagInput, setShowTagInput] = useState(false);

  const agentSessions = sessions.filter((s) => s.cwd === projectPath);

  const startEditing = useCallback((field: string, currentValue: string) => {
    setEditingField(field);
    setEditValue(currentValue);
  }, []);

  const commitEdit = useCallback(
    (field: string) => {
      if (editValue.trim()) {
        onUpdate({ [field]: editValue.trim() } as Partial<AgentManifest>);
      }
      setEditingField(null);
    },
    [editValue, onUpdate]
  );

  const handleAddTag = useCallback(() => {
    if (!newTag.trim()) return;
    const currentTags = (agent as Record<string, unknown>).tags as string[] ?? [];
    if (!currentTags.includes(newTag.trim())) {
      onUpdate({ tags: [...currentTags, newTag.trim()] } as unknown as Partial<AgentManifest>);
    }
    setNewTag('');
    setShowTagInput(false);
  }, [newTag, agent, onUpdate]);

  const handleRemoveTag = useCallback(
    (tag: string) => {
      const currentTags = (agent as Record<string, unknown>).tags as string[] ?? [];
      onUpdate({ tags: currentTags.filter((t) => t !== tag) } as unknown as Partial<AgentManifest>);
    },
    [agent, onUpdate]
  );

  return (
    <div className="space-y-4 p-4">
      {/* Display Name */}
      <div className="space-y-1">
        <label className="text-muted-foreground text-[10px] font-medium uppercase tracking-wider">
          Display Name
        </label>
        {editingField === 'displayName' ? (
          <Input
            autoFocus
            value={editValue}
            onChange={(e) => setEditValue(e.target.value)}
            onBlur={() => commitEdit('displayName')}
            onKeyDown={(e) => e.key === 'Enter' && commitEdit('displayName')}
            className="h-8 text-sm"
          />
        ) : (
          <button
            type="button"
            className="hover:bg-accent w-full rounded-md px-2 py-1 text-left text-sm transition-colors"
            onClick={() => startEditing('displayName', agent.displayName ?? agent.name)}
          >
            {agent.displayName ?? agent.name}
          </button>
        )}
      </div>

      {/* Description */}
      <div className="space-y-1">
        <label className="text-muted-foreground text-[10px] font-medium uppercase tracking-wider">
          Description
        </label>
        {editingField === 'description' ? (
          <textarea
            autoFocus
            value={editValue}
            onChange={(e) => setEditValue(e.target.value)}
            onBlur={() => commitEdit('description')}
            className="border-input bg-background text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:ring-ring w-full rounded-md border px-3 py-2 focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:outline-none"
            rows={3}
          />
        ) : (
          <button
            type="button"
            className="hover:bg-accent text-muted-foreground w-full rounded-md px-2 py-1 text-left text-sm transition-colors"
            onClick={() => startEditing('description', agent.description ?? '')}
          >
            {agent.description || 'Add a description...'}
          </button>
        )}
      </div>

      {/* Runtime */}
      <div className="space-y-1">
        <label className="text-muted-foreground text-[10px] font-medium uppercase tracking-wider">
          Agent Runtime
        </label>
        <Select
          value={agent.runtime ?? 'claude-code'}
          onValueChange={(v) => onUpdate({ runtime: v } as Partial<AgentManifest>)}
        >
          <SelectTrigger className="h-8 text-sm">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="claude-code">Claude Code</SelectItem>
            <SelectItem value="mock">Mock Runtime</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Directory */}
      <div className="space-y-1">
        <label className="text-muted-foreground text-[10px] font-medium uppercase tracking-wider">
          Directory
        </label>
        <div className="text-muted-foreground flex items-center gap-1.5 rounded-md px-2 py-1">
          <Folder className="size-3.5 shrink-0" />
          <span className="font-mono text-xs">{tildeShorten(projectPath)}</span>
        </div>
      </div>

      {/* Tags */}
      <div className="space-y-1">
        <label className="text-muted-foreground text-[10px] font-medium uppercase tracking-wider">
          Tags
        </label>
        <div className="flex flex-wrap items-center gap-1.5">
          {((agent as Record<string, unknown>).tags as string[] ?? []).map((tag) => (
            <span
              key={tag}
              className="bg-accent text-accent-foreground inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-xs"
            >
              {tag}
              <button
                type="button"
                onClick={() => handleRemoveTag(tag)}
                className="hover:text-destructive transition-colors"
                aria-label={`Remove tag ${tag}`}
              >
                <X className="size-3" />
              </button>
            </span>
          ))}
          {showTagInput ? (
            <Input
              autoFocus
              value={newTag}
              onChange={(e) => setNewTag(e.target.value)}
              onBlur={handleAddTag}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleAddTag();
                if (e.key === 'Escape') setShowTagInput(false);
              }}
              className="h-6 w-24 text-xs"
              placeholder="tag name"
            />
          ) : (
            <button
              type="button"
              onClick={() => setShowTagInput(true)}
              className="text-muted-foreground hover:text-foreground inline-flex items-center gap-0.5 text-xs transition-colors"
            >
              <Plus className="size-3" /> Add
            </button>
          )}
        </div>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-3 gap-2">
        <div className="bg-accent/50 rounded-lg p-3 text-center">
          <div className="text-lg font-semibold">{agentSessions.length}</div>
          <div className="text-muted-foreground text-[10px]">Sessions</div>
        </div>
        <div className="bg-accent/50 rounded-lg p-3 text-center">
          <div className="text-lg font-semibold">—</div>
          <div className="text-muted-foreground text-[10px]">Channels</div>
        </div>
        <div className="bg-accent/50 rounded-lg p-3 text-center">
          <div className="text-lg font-semibold">—</div>
          <div className="text-muted-foreground text-[10px]">Tasks</div>
        </div>
      </div>
    </div>
  );
}
```

Note: The channels and tasks stats use placeholder dashes for now. The spec mentions `useBindings()` and `useTaskRuns()` hooks — wire these in when they are available. The sessions count is computed from `useSessions()` filtered to projectPath.

